import React, { useState, useEffect } from 'react';
import axios from 'axios';

function AdminDashboard() {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  // 1. Fetch All Data
  useEffect(() => {
    fetchRequests();
  }, []);

  const fetchRequests = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
      setLoading(false);
    } catch (err) {
      console.error("Error fetching data:", err);
      setLoading(false);
    }
  };

  // 2. Generic Update Function (Updates any field in DB)
  const handleUpdate = async (id, updatedData) => {
    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, updatedData);
      fetchRequests(); // Refresh UI
    } catch (err) {
      alert("Error updating database!");
    }
  };

  // 3. Mark as Full Paid (Quick Action)
  const markAsFullPaid = (id, total) => {
    if (window.confirm("Mark this project as fully paid?")) {
      handleUpdate(id, { advancePaid: total, paymentStatus: 'Paid' });
    }
  };

  if (loading) return <div className="text-center py-5">Loading Admin Panel...</div>;

  return (
    <div className="container py-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h2 className="fw-bold mb-0">Admin <span className="text-primary">Control Panel</span></h2>
          <p className="text-muted">Track projects, update progress, and manage payments.</p>
        </div>
        <button className="btn btn-primary shadow-sm" onClick={fetchRequests}>
          <i className="fas fa-sync-alt me-2"></i> Refresh Data
        </button>
      </div>

      <div className="row g-3">
        {requests.map((project) => {
          const remaining = project.totalBudget - project.advancePaid;

          return (
            <div key={project._id} className="col-12">
              <div className="card shadow-sm border-0 rounded-4 p-4 mb-2">
                <div className="row align-items-center text-center text-md-start">
                  
                  {/* Column 1: Client Info */}
                  <div className="col-md-3">
                    <h5 className="fw-bold mb-0 text-capitalize">{project.fullName}</h5>
                    <small className="text-primary fw-bold text-uppercase d-block mb-1">{project.serviceType}</small>
                    <small className="text-muted">{project.email}</small>
                  </div>

                  {/* Column 2: Progress Control */}
                  <div className="col-md-3 px-md-4 py-3 py-md-0">
                    <div className="d-flex justify-content-between mb-1">
                      <small className="fw-bold text-muted">Progress</small>
                      <small className="fw-bold text-primary">{project.progress}%</small>
                    </div>
                    <div className="progress rounded-pill mb-2" style={{ height: '10px' }}>
                      <div className="progress-bar bg-primary" style={{ width: `${project.progress}%` }}></div>
                    </div>
                    <input 
                      type="range" className="form-range" min="0" max="100" 
                      value={project.progress} 
                      onChange={(e) => handleUpdate(project._id, { progress: e.target.value })}
                    />
                  </div>

                  {/* Column 3: Payment Tracking (Sir's Logic) */}
                  <div className="col-md-3 border-start border-end py-2">
                    {project.paymentStatus === 'Paid' ? (
                      <div className="text-center">
                        <span className="badge bg-success-light text-success p-2 px-3 rounded-pill fw-bold">
                          ✅ FULLY PAID
                        </span>
                        <div className="small mt-1 text-muted">Received: ₹{project.totalBudget}</div>
                      </div>
                    ) : (
                      <div className="px-3">
                        <small className="text-muted d-block text-center">Remaining Balance</small>
                        <h4 className="text-danger fw-bold mb-1 text-center">₹{remaining}</h4>
                        
                        <div className="d-flex justify-content-between align-items-center small">
                          <span>Total: ₹{project.totalBudget}</span>
                          <i className="fas fa-edit text-primary cursor-pointer" 
                            onClick={() => {
                              const budget = prompt("Enter Total Project Budget:", project.totalBudget);
                              if(budget) handleUpdate(project._id, { totalBudget: budget });
                            }}
                          ></i>
                        </div>
                        
                        <div className="d-flex justify-content-between align-items-center small mt-1">
                          <span>Paid: ₹{project.advancePaid}</span>
                          <i className="fas fa-pencil-alt text-warning cursor-pointer"
                            onClick={() => {
                              const paid = prompt("Update Advance/Paid Amount:", project.advancePaid);
                              if(paid) {
                                const status = Number(paid) >= project.totalBudget ? 'Paid' : 'Unpaid';
                                handleUpdate(project._id, { advancePaid: paid, paymentStatus: status });
                              }
                            }}
                          ></i>
                        </div>
                      </div>
                    )}
                  </div>

                  {/* Column 4: Actions */}
                  <div className="col-md-3 text-center text-md-end">
                    {project.paymentStatus !== 'Paid' ? (
                      <button 
                        className="btn btn-outline-success btn-sm px-4 rounded-pill fw-bold"
                        onClick={() => markAsFullPaid(project._id, project.totalBudget)}
                      >
                        Mark Full Paid
                      </button>
                    ) : (
                      <button className="btn btn-light btn-sm text-muted disabled rounded-pill border">Settled</button>
                    )}
                    <button 
                      className="btn btn-link text-danger ms-2"
                      onClick={async () => {
                        if(window.confirm("Delete this record permanently?")) {
                          await axios.delete(`http://localhost:5000/api/delete-request/${project._id}`);
                          fetchRequests();
                        }
                      }}
                    >
                      <i className="fas fa-trash"></i>
                    </button>
                  </div>

                </div>
              </div>
            </div>
          );
        })}
      </div>

      {requests.length === 0 && <div className="text-center py-5 text-muted">No client requests available.</div>}

      <style>{`
        .bg-success-light { background-color: #e8f5e9; }
        .cursor-pointer { cursor: pointer; font-size: 11px; }
        .cursor-pointer:hover { opacity: 0.7; }
        .form-range::-webkit-slider-thumb { background: #0d6efd; }
      `}</style>
    </div>
  );
}

export default AdminDashboard;
